+
+        String inputDir = args[0];
+        String outputDir = args.length > 1 ? args[1] : inputDir + "/spooned";
+
+        spoon.MavenLauncher launcher = new spoon.MavenLauncher(inputDir, spoon.MavenLauncher.SOURCE_TYPE.ALL_SOURCE);
+        launcher.getEnvironment().setNoClasspath(true);
+        launcher.getEnvironment().setAutoImports(true);
+        launcher.getEnvironment().setCommentEnabled(false);
+        launcher.buildModel();
+
+        spoon.reflect.factory.Factory factory = launcher.getFactory();
+
+        new spoon.processing.AbstractProcessor<spoon.reflect.declaration.CtElement>() {
+            @Override
+            public void process(spoon.reflect.declaration.CtElement element) {
+                if (element instanceof spoon.reflect.code.CtInvocation) {
+                    rewriteInvocation((spoon.reflect.code.CtInvocation<?>) element, factory);
+                } else if (element instanceof spoon.reflect.code.CtConstructorCall) {
+                    rewriteConstructorCall((spoon.reflect.code.CtConstructorCall<?>) element, factory);
+                } else if (element instanceof spoon.reflect.code.CtNewClass) {
+                    rewriteAnonymousCallback((spoon.reflect.code.CtNewClass<?>) element, factory);
+                } else if (element instanceof spoon.reflect.declaration.CtMethod) {
+                    rewriteCallbackMethod((spoon.reflect.declaration.CtMethod<?>) element, factory);
+                }
+            }
+
+            private void rewriteConstructorCall(spoon.reflect.code.CtConstructorCall<?> call, spoon.reflect.factory.Factory factory) {
+                if (!"com.pubnub.api.PNConfiguration".equals(qualifiedType(call.getType()))) {
+                    return;
+                }
+                if (!call.getArguments().isEmpty()) {
+                    return;
+                }
+
+                call.replace(factory.Code().createCodeSnippetExpression(
+                        "new com.pubnub.api.PNConfiguration(new com.pubnub.api.UserId(java.util.UUID.randomUUID().toString()))"));
+            }
+
+            private void rewriteInvocation(spoon.reflect.code.CtInvocation<?> invocation, spoon.reflect.factory.Factory factory) {
+                String targetType = qualifiedType(invocation.getTarget() == null ? null : invocation.getTarget().getType());
+                if (!"com.pubnub.api.PNConfiguration".equals(targetType)) {
+                    return;
+                }
+
+                String name = invocation.getExecutable().getSimpleName();
+                if ("setUuid".equals(name) && invocation.getArguments().size() == 1) {
+                    String arg = invocation.getArguments().get(0).toString();
+                    invocation.replace(factory.Code().createCodeSnippetExpression(
+                            "(" + targetExpr(invocation) + ").setUserId(new com.pubnub.api.UserId(" + arg + "))"));
+                } else if ("getUuid".equals(name) && invocation.getArguments().isEmpty()) {
+                    invocation.replace(factory.Code().createCodeSnippetExpression(
+                            "(" + targetExpr(invocation) + ").getUserId().getValue()"));
+                }
+            }
+
+            private void rewriteAnonymousCallback(spoon.reflect.code.CtNewClass<?> newClass, spoon.reflect.factory.Factory factory) {
+                if (!"com.pubnub.api.callbacks.SubscribeCallback".equals(qualifiedType(newClass.getType()))) {
+                    return;
+                }
+                newClass.setType(factory.Type().createReference("com.pubnub.api.callbacks.SubscribeCallback.BaseSubscribeCallback"));
+            }
+
+            private void rewriteCallbackMethod(spoon.reflect.declaration.CtMethod<?> method, spoon.reflect.factory.Factory factory) {
+                spoon.reflect.reference.CtTypeReference<?> parentType = method.getParent(spoon.reflect.declaration.CtType.class).getReference();
+                if (!"com.pubnub.api.callbacks.SubscribeCallback.BaseSubscribeCallback".equals(qualifiedType(parentType))
+                        && !"com.pubnub.api.callbacks.SubscribeCallback".equals(qualifiedType(parentType))) {
+                    return;
+                }
+
+                if (method.getParameters().size() != 1) {
+                    return;
+                }
+
+                String parameterType = qualifiedType(method.getParameters().get(0).getType());
+                if ("user".equals(method.getSimpleName())) {
+                    method.setSimpleName("uuid");
+                    method.getParameters().get(0).setType(factory.Type().createReference("com.pubnub.api.models.consumer.objects_api.uuid.PNUUIDMetadataResult"));
+                } else if ("space".equals(method.getSimpleName())) {
+                    method.setSimpleName("channel");
+                    method.getParameters().get(0).setType(factory.Type().createReference("com.pubnub.api.models.consumer.objects_api.channel.PNChannelMetadataResult"));
+                } else if ("membership".equals(method.getSimpleName())
+                        && "com.pubnub.api.models.consumer.pubsub.objects.PNMembershipResult".equals(parameterType)) {
+                    method.getParameters().get(0).setType(factory.Type().createReference("com.pubnub.api.models.consumer.objects_api.membership.PNMembershipResult"));
+                }
+            }
+
+            private String targetExpr(spoon.reflect.code.CtInvocation<?> invocation) {
+                return invocation.getTarget().toString();
+            }
+
+            private String qualifiedType(spoon.reflect.reference.CtTypeReference<?> type) {
+                return type == null ? null : type.getQualifiedName();
+            }
+        }.process(launcher.getModel());
+
+        launcher.setSourceOutputDirectory(new java.io.File(outputDir));
+        launcher.prettyprint();
     }
 }
*** End Patch

