private final ObjectMapper mapper;

public PubnubStreamingService(String publicKey) {
    mapper = new ObjectMapper();
    mapper.configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, false);
    PNConfiguration pnConfiguration;
    try {
        pnConfiguration = new com.pubnub.api.PNConfiguration(new com.pubnub.api.UserId(java.util.UUID.randomUUID().toString()));
    } catch (com.pubnub.api.PubNubException e) {
        throw new RuntimeException(e);
    }
    pnConfiguration.setSubscribeKey(publicKey);
    pubnub = new PubNub(pnConfiguration);
    pnStatusCategory = PNStatusCategory.PNDisconnectedCategory;
}

public Completable connect() {
    return Completable.create(e -> {
        pubnub.addListener(new BaseSubscribeCallback() {
            @Override
